const banned = ['authorization_token', 'api_key', 'secret', 'password', 'bearer ', 'jwt ', 'phone_number', 'owner', 'respondent'];
const payload = JSON.stringify(items.map(i => i.json));
const lower = payload.toLowerCase();
const found = banned.filter(term => lower.includes(term));
if (found.length) {
  throw new Error(`Formaloo payload failed safety scan: ${found.join(', ')}`);
}
return [{ json: { ok: true, checked_at: new Date().toISOString(), summaries: items.map(i => i.json) } }];
